509	func logPreClaimIntakeRoute(w io.Writer, beadID string, runtime AgentRunRuntime, verbose bool) {
510		if w == nil || !verbose {
511			return
512		}
513		if route := preClaimIntakeRouteSummary(runtime); route != "" {
514			_, _ = fmt.Fprintf(w, "readiness prompt %s: route %s\n", beadID, route)
515		}
516	}
