848	func failedReadinessReasons(checks []preClaimReadinessCheck) []string {
849		reasons := make([]string, 0, len(checks))
850		for _, check := range checks {
851			verdict := strings.ToLower(strings.TrimSpace(string(check.Verdict)))
852			if verdict != "fail" {
853				continue
854			}
855			if reason := strings.TrimSpace(check.Reason); reason != "" {
856				reasons = append(reasons, reason)
857			}
858		}
859		return reasons
860	}
