3781	func (s *preClaimWarnRepeatState) reset(fingerprint, beadID, detail string, payload map[string]any, at time.Time) {
3782		s.Fingerprint = fingerprint
3783		s.Count = 1
3784		s.DistinctBeadIDs = []string{beadID}
3785		if s.seenBeadIDs == nil {
3786			s.seenBeadIDs = map[string]struct{}{}
3787		} else {
3788			for k := range s.seenBeadIDs {
3789				delete(s.seenBeadIDs, k)
3790			}
3791		}
3792		if beadID != "" {
3793			s.seenBeadIDs[beadID] = struct{}{}
3794		}
3795		s.ExampleBeadID = beadID
3796		s.ExampleDetail = detail
3797		s.ExamplePayload = cloneStringAnyMap(payload)
3798		s.FirstObservedAt = at.UTC()
3799		s.EscalationIssued = false
3800	}
