3802	func (s *preClaimWarnRepeatState) record(fingerprint, beadID, detail string, payload map[string]any, at time.Time, threshold int) (preClaimWarnRepeatState, bool) {
3803		if threshold <= 0 {
3804			threshold = DefaultPreClaimWarnRepeatThreshold
3805		}
3806		if fingerprint == "" {
3807			return preClaimWarnRepeatState{}, false
3808		}
3809		if s.Count == 0 || s.Fingerprint != fingerprint || s.seenBeadIDs == nil {
3810			s.reset(fingerprint, beadID, detail, payload, at)
3811			return *s, false
3812		}
3813		if _, seen := s.seenBeadIDs[beadID]; seen {
3814			s.reset(fingerprint, beadID, detail, payload, at)
3815			return *s, false
3816		}
3817		s.Count++
3818		s.DistinctBeadIDs = append(s.DistinctBeadIDs, beadID)
3819		s.seenBeadIDs[beadID] = struct{}{}
3820		if s.ExampleBeadID == "" {
3821			s.ExampleBeadID = beadID
3822		}
3823		if s.ExampleDetail == "" {
3824			s.ExampleDetail = detail
3825		}
3826		if len(s.ExamplePayload) == 0 {
3827			s.ExamplePayload = cloneStringAnyMap(payload)
3828		}
3829		if s.FirstObservedAt.IsZero() {
3830			s.FirstObservedAt = at.UTC()
3831		}
3832		if s.Count >= threshold && !s.EscalationIssued {
3833			s.EscalationIssued = true
3834			return *s, true
3835		}
3836		return *s, false
3837	}
