3839	func cloneStringAnyMap(src map[string]any) map[string]any {
3840		if len(src) == 0 {
3841			return nil
3842		}
3843		dst := make(map[string]any, len(src))
3844		for k, v := range src {
3845			dst[k] = v
3846		}
3847		return dst
